module garage_door (
	input clk,
	input resetn,
	input open,
	input close,
	output reg door_open);

	parameter CLOSED=0, OPEN=1;
	reg obf_state, next_state;

	always @(posedge clk) begin
		if (~resetn) obf_state <= CLOSED;
		else obf_state <= next_state;
	end

	always_comb begin
		case (obf_state)
			CLOSED: next_state = open ? OPEN : CLOSED;
			OPEN: next_state = close ? CLOSED : OPEN;
			default: next_state = CLOSED;
		endcase
	end

	always @(obf_state) begin
		case (obf_state)
			OPEN: door_open = 1;
			default: door_open = 0;
		endcase
	end
endmodule
